package data

import (
	_ "embed"
	"encoding/json"
)

//go:embed system_prompt.txt
var SystemPrompt string

//go:embed tools.json
var toolsJSON []byte

// Tools returns the full 28 Claude Code tools array parsed from embedded JSON.
func Tools() []any {
	var tools []any
	json.Unmarshal(toolsJSON, &tools)
	return tools
}

// TestImagePNG is a small 288x90 PNG image containing text for OCR testing.
// The expected OCR result is checked by the image_ocr probe.
const TestImagePNG = ""

// TestDocPDF is a minimal single-page PDF containing the text "BYPWNXWP".
const TestDocPDF = ""
